  --background-root: var(--default-surface-color-000);
  --background-default: var(--default-surface-color-100);
  --background-higher: var(--default-surface-color-300);
  --background-highest: var(--default-surface-color-500);
  --background-overlay: color-mix(in srgb, var(--default-surface-color-100) 63%, transparent);
  --foreground-default: var(--default-text-color-1500);
  --foreground-dimmer: var(--default-text-color-900);
  --foreground-dimmest: var(--default-text-color-300);
  --outline-dimmest: var(--default-surface-color-800);
  --outline-dimmer: var(--default-surface-color-1200);
  --outline-default: var(--default-surface-color-1600);
  --outline-stronger: var(--default-surface-color-1600);
  --outline-strongest: var(--default-surface-color-1600);
  --accent-primary-dimmest: var(--primary-surface-color--1400);
  --accent-primary-dimmer: var(--primary-surface-color--1000);
  --accent-primary-default: var(--primary-surface-color-000);
  --accent-primary-stronger: var(--primary-surface-color--100);
  --accent-primary-strongest: var(--primary-surface-color-200);
  --accent-positive-dimmest: var(--positive-surface-color-000);
  --accent-positive-dimmer: var(--positive-surface-color-100);
