<hr>
<div class=" useView-module__vOh_Ha__view Markdown-module__r02qCW__messageMarkdownHeading"><span class=" useView-module__vOh_Ha__view Text-module__KIh4Sq__text Text-module__KIh4Sq__multiline _sdz_text" style="--Text--font-family: inherit; --Text--font-size: var(--font-size-default); --Text--line-height: var(--line-height-default);"><strong>Langkah 2 — Buka proyek di Cursor</strong></span></div>
<ol>
